import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,d as t}from"./app-2a68677b.js";const o={},p=t(`<h1 id="cpython的内存概念栈、堆和引用" tabindex="-1"><a class="header-anchor" href="#cpython的内存概念栈、堆和引用" aria-hidden="true">#</a> CPython的内存概念栈、堆和引用</h1><p>Python的实现版本有很多，例如Jython底层就是<code>JVM</code>, IronPython的底层是<code>.Net</code>，它们的内存管理千差万别取决于底层的运行时系统。在CPython实现中，堆和栈有各自的职责。</p><blockquote><p><strong>C语言</strong></p></blockquote><p>堆(<code>heap</code>)和栈(<code>stack</code>)原本是两种不同的数据结构，在C语言内存表述中，代表着用这两种数据结构管理的两种内存块。</p><p>堆由整个系统共享，各个进程拥有同一个堆。 栈由每个进程自行管理，也就是每个进程的栈是独立的，互不相关。</p><p><strong>具体区别如下:</strong></p><ol><li>栈上的内存由系统自动管理分配，用于存储局部变量。 堆中的内存由编程人员主动申请，在C语言中申请内存的函数为malloc， 使用后需要编程人员自行调用free函数释放。</li><li>从分配释放及访问速度上，栈内存的存取，申请释放速度要高于堆内存。</li><li>栈内存相对于堆内存要小的多，所以在编程的时候，一般不建议使用占空间过大的局部变量。</li><li>堆中所有数据均由编程人员申请使用。 栈中除了存放函数中可见的局部变量外，还有各种系统环境数据。</li></ol><blockquote><p><strong>python语言</strong></p></blockquote><p><strong>堆</strong>: 主要负责存储CPython运行时的所有对象实体(也就是Python对象的所有属性数据)，例如:<code>smt=&#39;Hello Word&#39;</code>这个字符串对象PyASCIIObject，<code>n=23</code>这是一个整数PyLongObject，它们都是Python对象,赋值符号<code>=</code>右边的数据值，CPython会将其存储到堆内存中。</p><p><strong>栈</strong>: 在CPython的语义中，又叫数据栈或值栈，它主要负责保存对堆中Python对象的引用，例如：当CPython在执行<code>smt=&#39;Hello Word&#39;</code>这个简单的Python语句，CPython会将<code>&#39;Hello Word&#39;</code>这个字符串实体所处的内存地址压入栈(对于Python语义级别理解，就是对<code>&quot;Hello Word&quot;</code>的引用)，而不是将<code>&#39;Hello Word&#39;</code>这个字符串值压入栈。</p><p><code>smt=&#39;Hello Word&#39;</code>这些简单的Python赋值语句，你不能单纯地认为将<code>&#39;Hello World&#39;</code>赋值给变量<code>smt</code>，这是大错特错的。</p><p>赋值符号右边的是Python对象实体(从C实现的理解，就是构成该PyObject子类对象的属性值，这些值有具体的字面量值表示)，并且CPython会为该Python对象在堆中分配内存并且存储它。</p><p>而变量<code>smt</code>仅持有该Python对象实体的引用(从C实现的理解，就是该PyObject对象的内存地址)，而不是实际的Python对象。</p><p>s1变量持有Python对象<code>&#39;Hello world&#39;</code>的引用，对于CPython虚拟机来说，就是在执行<code>s1=&#39;Hello Word&#39;</code>，将它的内存地址<code>0x71334</code>推入数据栈，那么当CPython碰到同样的语句<code>s2=&#39;Hello Word&#39;</code>，明显是指向同一个Python对象，那么变量s2和s1一样,它自然持有是<code>&#39;Hello Word&#39;</code>的引用,即s2实质上拥有的<code>&#39;Hello Word&#39;</code>的堆中的地址。</p><figure><img src="https://img.bookandmusic.cn/blog/2022/01/e4mAxt.png" alt="e4mAxt" tabindex="0" loading="lazy"><figcaption>e4mAxt</figcaption></figure><p>对于其他简易的数据类型，也是如出一辙的。那么现在给Python引用我们可以下一个定义。</p><p>Python对象的引用:就是Python变量持有Python对象在堆内存中的内存地址。</p><p>我们可以通过python的内置<code>id</code>函数或者关键字<code>is</code> 来判断两个变量是否对同一个对象的引用。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>In <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">:</span> s1 <span class="token operator">=</span> <span class="token string">&#39;hello world&#39;</span>

In <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span><span class="token punctuation">:</span> s2 <span class="token operator">=</span> <span class="token string">&#39;hello world&#39;</span>

In <span class="token punctuation">[</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token builtin">id</span><span class="token punctuation">(</span>s1<span class="token punctuation">)</span>
Out<span class="token punctuation">[</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token number">4472932144</span>

In <span class="token punctuation">[</span><span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token builtin">id</span><span class="token punctuation">(</span>s2<span class="token punctuation">)</span>
Out<span class="token punctuation">[</span><span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token number">4472034928</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在Python中有两种类型的对象：可变对象和不可变对象。</p><p>可变对象: 比较典型的就是list，一个列表作为一个对象存储在堆内存中，如果我们要更改该列表的某些元素，它将仍然是内存中的同一个列表对象。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>In <span class="token punctuation">[</span><span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">:</span> alist <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span>

In <span class="token punctuation">[</span><span class="token number">6</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token builtin">id</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span> <span class="token keyword">for</span> x <span class="token keyword">in</span> alist<span class="token punctuation">]</span>
Out<span class="token punctuation">[</span><span class="token number">6</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token number">4439298464</span><span class="token punctuation">,</span> <span class="token number">4439298496</span><span class="token punctuation">,</span> <span class="token number">4439298528</span><span class="token punctuation">]</span>

In <span class="token punctuation">[</span><span class="token number">7</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token builtin">id</span><span class="token punctuation">(</span>alist<span class="token punctuation">)</span>
Out<span class="token punctuation">[</span><span class="token number">7</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token number">4474113152</span>

In <span class="token punctuation">[</span><span class="token number">8</span><span class="token punctuation">]</span><span class="token punctuation">:</span> alist<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token operator">=</span> <span class="token number">22</span>

In <span class="token punctuation">[</span><span class="token number">9</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token builtin">id</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span> <span class="token keyword">for</span> x <span class="token keyword">in</span> alist<span class="token punctuation">]</span>
Out<span class="token punctuation">[</span><span class="token number">9</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token number">4439298464</span><span class="token punctuation">,</span> <span class="token number">4439299136</span><span class="token punctuation">,</span> <span class="token number">4439298528</span><span class="token punctuation">]</span>

In <span class="token punctuation">[</span><span class="token number">10</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token builtin">id</span><span class="token punctuation">(</span>alist<span class="token punctuation">)</span>
Out<span class="token punctuation">[</span><span class="token number">10</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token number">4474113152</span>
    
In <span class="token punctuation">[</span><span class="token number">11</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token builtin">id</span><span class="token punctuation">(</span><span class="token number">22</span><span class="token punctuation">)</span>
Out<span class="token punctuation">[</span><span class="token number">11</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token number">4439299136</span>

In <span class="token punctuation">[</span><span class="token number">12</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token builtin">id</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span>
Out<span class="token punctuation">[</span><span class="token number">12</span><span class="token punctuation">]</span><span class="token punctuation">:</span> <span class="token number">4439298464</span>    
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在列表<code>alist</code>中，通过列表表达式打印出列表每个对象元素的内存地址，以及列表对象<code>alist</code>本身的内存地址，然后在修改列表元素后，再次打印列表对象中的各个对象元素的内存地址，以及<code>alist</code>本身的内存地址。</p><p>这段代码告诉我们CPython在内存中有如下事实</p><p><code>list</code>类型的<code>alist</code>本身是一个Python对象，其对象实体就是在<strong>堆内存</strong>中。<br><code>list</code>类型的对象,作为一个容器级别的对象，其<strong>列表存储的是元素实体的引用，而非元素实体本身</strong>。</p><p>对<code>list</code>对象中的某个元素的修改的本质是<strong>令被修改元素指向其他元素的引用</strong>，而我们修改该元素时,实际上CPython在堆内存中创建了一个新的对象(本例中的整数22)分配新的内存空间，并且保存该新增的对象(整数22)。<code>alist</code>的第三个元素不再对2的引用，更新为对22的引用。</p><p><code>list</code>类型对象的在其元素修改前后,变量<code>alist</code>始终引用同一个<code>list</code>对象。</p><p>那么从上面的例子，我们得知：</p><p>**可变对象的实质:**其内部元素可修改是可变更对其他Python对象的引用。其可变对象的元素可以是数字、字符串，甚至可以是其他容器级别的可变对象。</p><p><strong>不可变对象</strong>：就非常容易理解了,上面示例中list的元素对象都是不可变对象。推而广之，Python中的原始数据类型,例如数字类型(int,float)、字符串(str)、字节数组(bytes)。</p><p>在Python中，一切事物都是对象,不论是整数，字符串，甚至是其他容器级别的数据类型,都由CPython的C底层由一个叫<code>struct PyObject</code>结构体所封装。PyObject的结构体在CPython运行时存储在堆内中。</p><blockquote><p><strong>小结</strong></p></blockquote><p>我们从堆内存的角度理解，为什么CPython要对Python对象分为：可变对象和不可变对象，初衷是尽可能低简化堆内存的分配。因为Python变量持有Python对象的引用(或者从C底层去理解，持有PyObject对象的指针)去访问Python对象实体本身，比持有一个Python对象实体的副本更高效，更节省堆和栈的内存开销。</p><p>那么当多个Python变量引用同一个Python对象就涉及到概念就引用计数器，引用计数器属于内存垃圾回收的范畴，由引用计数又会牵涉到CPython一个致命的诟病，GIL:全局解释器锁，为什么多年来CPython不能去掉GIL，很大原因跟引用计数器有关。</p>`,34),e=[p];function c(l,u){return s(),a("div",null,e)}const k=n(o,[["render",c],["__file","CPython的内存概念栈、堆和引用.html.vue"]]);export{k as default};
